CREATE TABLE IF NOT EXISTS privacy_compliance_evidence(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,control text NOT NULL,source text NOT NULL,reference text NOT NULL,status text NOT NULL DEFAULT 'collected',collected_at timestamptz NOT NULL,reviewer text NOT NULL DEFAULT '',review_note text NOT NULL DEFAULT '',reviewed_at timestamptz,metadata jsonb NOT NULL DEFAULT '{}'::jsonb,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS privacy_compliance_reports(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,period_start timestamptz NOT NULL,period_end timestamptz NOT NULL,status text NOT NULL DEFAULT 'draft',summary jsonb NOT NULL DEFAULT '{}'::jsonb,generated_at timestamptz,published_at timestamptz,metadata jsonb NOT NULL DEFAULT '{}'::jsonb,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now(),CHECK(period_end >= period_start));
CREATE INDEX IF NOT EXISTS idx_privacy_evidence_control ON privacy_compliance_evidence(tenant_id,control,status); CREATE INDEX IF NOT EXISTS idx_privacy_reports_period ON privacy_compliance_reports(tenant_id,period_end,status);
